"""
MKT Context Commentary — Genesis chapters 33–35
Run: python3 scripts/zc-context-genesis-33-35.py

Source data used:
- data/interlinear/genesis.json
- data/translation/draft/mediating/genesis.json (MKT text)
- data/commentary/mkt-context/genesis.json (prior chapters; merge_comm skips already-present entries)

Key decisions in this range:
- Ch33:v3 seven prostrations: this is documented Amarna-letter protocol for vassals before overlords;
  the count is specific, not figurative, and signals full submission
- Ch33:v10 "face of God": ANE court formula — seeing the king's face in favor was the highest social
  boon; Jacob applies this language to Esau to honor him while also acknowledging the divine in
  Esau's unexpected generosity
- Ch33:v11 "blessing" returned to Esau: Jacob calls the gift a minhāh (tribute/gift) but then calls
  it birkātî (my blessing) — deliberately echoing the stolen blessing of ch.27; partial restitution
- Ch34:v7 "folly in Israel": a technical legal formula (nĕḇālāh bĕyiśrāʾēl) that recurs in
  2 Sam 13:12 and Judg 19-20 for gross violations of covenant community standards
- Ch34:v13 "replied deceitfully": the narrator explicitly labels this mirmāh — the same word
  for Jacob's deception of Isaac in ch.27; the pattern of deception continues in the next generation
- Ch34:v25 three days: the third day after circumcision is the most painful; Simeon and Levi
  chose the timing for maximum incapacitation of the Shechemite men
- Ch35:v4 earrings buried with idols: in the ANE, earrings and nose rings often functioned as
  amulets or were associated with protective deities; burying them signals religious purification
- Ch35:v8 Deborah's death: Rebekah's nurse — last mentioned traveling with Rebekah in 24:59;
  decades later she is with Jacob's household (perhaps Rebekah had died); her burial under
  an "oak of weeping" is a tenderness rarely shown for servants in ANE narrative
- Ch35:v22 Reuben and Bilhah: sleeping with a father's concubine was an ANE act of claiming
  succession/dominance; cf. Absalom (2 Sam 16:21); it costs Reuben his firstborn privileges (49:3-4)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS = {
  "33": {
    "1": '<p>"Jacob looked up and there was Esau, coming with his four hundred men; so he divided the children among Leah, Rachel and the two female servants" — the arrangement follows a logic of vulnerability and preference. Those placed in front face the greatest risk if Esau\'s approach turns hostile; those in back are most protected. The maidservants and their children go first (least preferred), Leah and her children second, Rachel and Joseph last (most protected). The ordering reflects Jacob\'s emotional hierarchy and his calculated self-preservation under existential threat.</p>',

    "2": '<p>"He put the female servants and their children in front, Leah and her children next, and Rachel and Joseph in the rear" — the family is arranged as a tactical formation for a potentially hostile encounter. Four hundred armed men accompanying a brother who vowed murder twenty years earlier (27:41) justified precaution. The sequence — maidservants, Leah, Rachel — exactly inverts the order of emotional priority: the least-loved first, the most-loved last. Jacob\'s love hierarchy becomes a survival strategy, with his most cherished placed furthest from danger.</p>',

    "3": '<p>"He himself went on ahead and bowed down to the ground seven times as he approached his brother" — the seven prostrations is the specific ANE protocol for a subject approaching an overlord or king. The Amarna letters (14th century BCE diplomatic correspondence between Canaanite vassal kings and Egypt) repeatedly use the formula "at the feet of my lord the king, seven times and seven times I fall" as the formal submission greeting. By prostrating seven times, Jacob is performing the full ritual of vassalage — not merely bowing politely but performing the complete submission ceremony. The gesture is not hyperbolic; it is precisely calibrated.</p>',

    "4": '<p>"Esau ran to meet Jacob and embraced him; he threw his arms around his neck and kissed him. And they wept" — Esau\'s response inverts every expectation the preceding chapters have set up. After twenty years and a murder vow (27:41), the reunion is instant, physical, and mutual. The sequence — running, embracing, neck, kiss, weeping — mirrors the prodigal son narrative in Luke 15:20 ("his father saw him and was filled with compassion for him; he ran to his son, threw his arms around him and kissed him"). Whether Luke consciously echoes this scene, the gesture-pattern of the father\'s reconciling love was already established in Genesis. The Masoretic text has a dot over each letter of "kissed" (<em>wayyiššāqēhû</em>), signaling scribal uncertainty or highlighting the surprising sincerity of the act.</p>',

    "5": '<p>"Who are these with you?" — Esau\'s question is the standard polite inquiry upon encountering a large family group. Jacob\'s answer — "They are the children God has graciously given your servant" — frames his family as divine gifts, using the self-lowering title "your servant" (<em>ʿaḇdĕkhā</em>) throughout this conversation. In the ANE honor-shame framework, the defeated or subordinate party routinely addressed the dominant party as "my lord" (<em>ʾăḏōnî</em>) and called himself "your servant" — a verbal enactment of the social hierarchy being acknowledged.</p>',

    "6": '<p>"The female servants and their children approached and bowed down" — the bowing follows the procession order of v.2: maidservants first. The formal bowing (<em>wayyištaḥăwû</em>, they prostrated themselves) is the same gesture Jacob performed seven times in v.3. Each family unit bows before Esau — a full household recognition of Esau\'s overlord status, consistent with the Amarna-letter protocol of collective submission.</p>',

    "7": '<p>"Leah and her children came and bowed down. Last of all came Joseph and Rachel, and they too bowed down" — the presentation sequence completes the protocol of v.3. Rachel\'s bowing before Esau is the culmination — the most honored wife presenting herself last. The multiple bowings throughout the meeting enact the vassalage formulas Jacob invokes verbally throughout the conversation. In Joseph\'s later dream (37:9-10), the sun and moon and stars bowing before him — which Jacob interprets as himself, Rachel, and the brothers — echoes this same gesture pattern.</p>',

    "8": '<p>"What\'s the meaning of all these flocks and herds I met?" — Esau encountered Jacob\'s advance gift of 550 animals sent in waves in ch.32:13-21. Jacob\'s answer — "to find favor in your eyes, my lord" (<em>limṣōʾ-ḥēn bĕʿênê ʾăḏōnî</em>) — uses the court formula of seeking royal approval. The gift had been calculated as a tribute to a potentially hostile overlord; Esau\'s question opens the formal acceptance or rejection of the tribute.</p>',

    "9": '<p>"I already have plenty, my brother. Keep what you have for yourself" — Esau\'s refusal of the gift is one of the chapter\'s most remarkable moments. A man who has four hundred armed men could simply take what he wants; instead he demonstrates magnanimity — a quality associated with the truly powerful in ANE honor-shame culture. The term "my brother" (<em>ʾāḥî</em>) rather than "your servant" signals Esau\'s desire to restore the relationship to equality rather than maintain the lord/servant dynamic Jacob has adopted.</p>',

    "10": '<p>"To see your face is like seeing the face of God, now that you have received me favorably" — the phrase "face of God" (<em>pĕnê ʾĕlōhîm</em>) is a court formula. In the ANE, "seeing the face" of a king or overlord meant being admitted to the royal presence in favor — denied audiences could mean death (cf. Esth 4:11). To see Esau\'s face and be received well is compared to encountering a divine royal presence with mercy rather than wrath. Jacob may also be alluding to his Peniel encounter (32:30: "I saw God face to face, and yet my life was spared") — seeing Esau\'s forgiveness mirrors the divine forgiveness of Peniel.</p>',

    "11": '<p>"Please accept the blessing I have brought you" (<em>qah-nāʾ ʾet-birkatî</em>) — Jacob calls the gift a <em>birkāh</em> (blessing), not the more neutral <em>minhāh</em> (tribute/gift) he used in 32:13 and 32:18. The word choice appears deliberate: the stolen "blessing" of ch.27 is being partially returned — Jacob is giving back what was taken by fraud. Esau accepts only after Jacob insists, which maintains Esau\'s dignity: he accepts not out of need but as a gracious act toward his brother.</p>',

    "12": '<p>"Let us be on our way; I\'ll accompany you" — Esau\'s offer to travel together is a generous gesture of restored kinship — brothers journeying together, not as lord and vassal. Jacob\'s subsequent demurral (vv.13-15) declines the offer without causing offense, using the practical excuse of vulnerable livestock and children. Whether Jacob is genuinely cautious about the pace or simply reluctant to travel with Esau toward Seir (which he has no intention of reaching), the narrative does not resolve.</p>',

    "13": '<p>"The children are tender and the ewes and cows that are nursing their young. If they are driven hard just one day, all the animals will die" — Jacob\'s excuse is practically sound. In ANE pastoral contexts, driving nursing animals and young children at a warrior\'s marching pace was genuinely dangerous. Nursing ewes and cows deprived of rest could suffer milk loss, mastitis, or miscarriage; young lambs and calves without adequate rest and feeding could die within a day of hard travel. The excuse is not implausible, though its timing as a pretext for avoiding Esau\'s company is also evident.</p>',

    "14": '<p>"Let my lord go on ahead of his servant, while I move along slowly at the pace of the flocks and herds before me and the pace of the children, until I come to my lord in Seir" — Jacob proposes to follow Esau to Seir (Edom\'s territory, southeast of the Dead Sea) — a promise he will not keep; he goes to Succoth and then Shechem, the opposite direction. Whether this is an intentional deception or a stated intention that Jacob subsequently changed, the narrative does not return to explain. The promise to come to Seir remains unfulfilled in the text.</p>',

    "15": '<p>"Then let me leave some of my men with you" — Esau\'s second offer (an armed escort) is also declined. Jacob\'s response — "Just let me find favor in the eyes of my lord" — uses the same court formula of v.8. The offer of armed men is a genuine act of provision and protection in an area where Jacob\'s household could be vulnerable; Jacob\'s refusal preserves his independence and avoids the continued obligation of Esau\'s presence.</p>',

    "16": '<p>"So that day Esau started on his way back to Seir" — the reconciliation is complete and the brothers separate. Esau returns to his territory (Seir = Edom, the highland plateau southeast of the Dead Sea) while Jacob goes in the opposite direction. The parting is peaceful; the twenty-year estrangement has been resolved without incident. The narrative does not indicate when or whether the brothers meet again until Isaac\'s death in 35:29.</p>',

    "17": '<p>"Jacob went to Succoth, where he built a place for himself and made shelters for his livestock. That is why the place is called Succoth" — <em>Sukkôt</em> (booths/shelters) takes its name from the temporary structures Jacob builds for his livestock. The place is in the Jordan valley east of the river, near the confluence of the Jabbok (Peniel area). Jacob had just wrestled with God at Peniel and met Esau at the ford; Succoth is his first settlement point back on the east bank. The Festival of Booths (<em>Sukkôt</em>) in the later Mosaic calendar commemorates the wilderness shelter period — the same word used here creates an etymological connection.</p>',

    "18": '<p>"Jacob came from Paddan Aram, he arrived safely at the city of Shechem in Canaan" — <em>šālēm</em> (safely/in peace) describes Jacob\'s condition on arrival; some translations read it as a place name ("the city of Salem"), but the context favors the adverbial reading. Shechem is one of the most strategically significant cities in Canaan\'s central highlands — located in a pass between Mount Gerizim and Mount Ebal, controlling north-south trade routes. Abraham had passed through Shechem and built an altar there (12:6). Jacob\'s arrival at Shechem connects him to the same covenant geography Abraham traveled.</p>',

    "19": '<p>"For a hundred pieces of silver, he bought from the sons of Hamor... the plot of ground where he pitched his tent" — the land purchase follows the pattern of Abraham\'s purchase of the Machpelah cave (ch.23): Jacob pays silver to acquire legal title rather than simply occupying the land. The "hundred pieces of silver" (<em>mēʾāh qĕśîṭāh</em>) — the <em>qĕśîṭāh</em> is an archaic unit of unknown weight, mentioned only here and in Job 42:11 and Josh 24:32 — signals a formal commercial transaction. Hamor is the father of Shechem (who will appear prominently in ch.34), and this purchase establishes the family\'s legal presence in the area.</p>',

    "20": '<p>"He set up an altar and called it El Elohe Israel" — "God, the God of Israel" (<em>ʾēl ʾĕlōhê yiśrāʾēl</em>). This is the first time Jacob uses his new name Israel in a liturgical context — the altar is named with both the divine title (<em>ʾēl</em>) and his new covenant identity. The altar marks the first worship act in the promised land since Jacob returned; it corresponds to Abraham\'s altar at Shechem (12:7) and Isaac\'s altars at Beersheba (26:25). The name embedded in the altar title also formally plants Jacob\'s identity as Israel in Canaan\'s most important city.</p>',
  },
  "34": {
    "1": '<p>"Dinah, the daughter Leah had borne to Jacob, went out to visit the women of the land" — Dinah\'s brief introduction (30:21 was her birth notice, without the naming formula given to her brothers) is now expanded. Going out to visit the women of the land was a socially normal activity in pastoral society, where young women\'s mobility was not as restricted as in urban settings. The narrator identifies her through her mother Leah rather than her father Jacob — emphasizing the matrilineal dimension before the patrilineal response dominates the narrative.</p>',

    "2": '<p>"Shechem son of Hamor the Hivite, the ruler of that area, saw her, he took her and raped her" — the narrative is unambiguous: <em>wayyiqqaḥ ʾōtāh wayyiškaḇ ʾōtāh wayyĕʿannehā</em> (he took her and lay with her and humiliated/violated her). The verb <em>ʿinnāh</em> (to violate/humiliate/afflict) is the standard OT term for rape (cf. 2 Sam 13:12, 14, 22, 32 — Amnon and Tamar). Shechem is identified as son of Hamor (whose name means "donkey" — possibly a clan or personal name) and as the Hivite ruler of the area — a person of significant political authority whose action has both personal and political dimensions.</p>',

    "3": '<p>"His heart was drawn to Dinah... he loved the young woman and spoke tenderly to her" — the narrator presents Shechem\'s emotional state after the rape: attraction, love, and tender speech. "Spoke tenderly" (<em>waydabbēr ʿal-lēḇ hannaʿărāh</em>, spoke to the heart of the young woman) is the same idiom used for comforting speech in Isa 40:2 and Ruth 2:13. The juxtaposition of rape and subsequent "love" is not reconciliation of the act but characterization of Shechem as someone who desired what he violated — a dimension of the ANE male-centered view of sexual possession that the narrative presents without endorsing.</p>',

    "4": '<p>"Shechem said to his father Hamor, \'Get me this girl as my wife\'" — marriage after rape was a recognized (if morally disturbing) resolution in ANE law. Deut 22:28-29 legislates that a man who rapes an unbetrothed virgin must pay the bride price and marry her (and cannot divorce her). The Shechemite request follows this legal framework: Shechem wants formal marriage, not merely possession. That the ANE legal remedy existed does not justify the rape, but it contextualizes why Hamor\'s subsequent negotiation (rather than Jacob\'s retaliation) is the expected social response.</p>',

    "5": '<p>"Jacob heard that his daughter Dinah had been defiled (<em>ṭimmēʾ</em>), his sons were in the fields with his livestock; so he did nothing about it until they came home" — Jacob\'s waiting for his sons is practical — decisions about marriage and family honor required the household\'s male leadership — but his silence throughout the negotiations that follow is also noteworthy. The defilement vocabulary (<em>ṭimmēʾ</em>, to make ritually/socially impure) frames the assault as a violation not just of Dinah personally but of the household\'s covenant purity — the same word used for sexual violations in Lev 18 and Num 5.</p>',

    "6": '<p>"Shechem\'s father Hamor went out to talk with Jacob" — the formal negotiation is conducted between the household heads. Hamor, as the city ruler and Shechem\'s father, has the authority to negotiate on behalf of the Shechemite community. Jacob, as the patriarch of his household, is the corresponding party. The negotiation follows standard ANE marriage-arrangement protocol: the fathers negotiate while the sons are involved as direct parties. The departure from protocol is that this negotiation is about repairing a violation, not initiating a legitimate courtship.</p>',

    "7": '<p>"They were shocked and furious, because Shechem had done an outrageous thing in Israel by sleeping with Jacob\'s daughter — a thing that should not be done" — the phrase <em>nĕḇālāh ʿāśāh bĕyiśrāʾēl</em> (he committed a folly/outrage in Israel) is a technical legal formula that recurs in the OT for gross violations of covenant community standards. In 2 Sam 13:12, Tamar uses virtually identical language to Amnon before he rapes her: "such a thing should not be done in Israel." In Judg 19-20 (the Gibeah incident), the same formula frames the community\'s response. The expression functions as a legal finding: this act violates the basic standards of the covenant community.</p>',

    "8": '<p>"My son Shechem has his heart set on your daughter. Please give her to him as his wife" — Hamor\'s appeal to Jacob is framed entirely in terms of Shechem\'s desire, not Dinah\'s welfare or Jacob\'s injury. The ANE marriage negotiation was primarily between the households\' male heads; Dinah\'s own perspective is not sought or mentioned. Hamor\'s proposal — marriage — is the legally recognized resolution, but the narrative frames it as insufficient given the violation that preceded it.</p>',

    "9": '<p>"Intermarry with us; give us your daughters and take our daughters for yourselves" — Hamor\'s broader proposal goes beyond the single case: full intermarriage between Jacob\'s household and the Shechemite community. In ANE terms, this was a proposal for covenant alliance — the sharing of daughters in marriage created kinship bonds that were the foundation of political alliances and social integration. The proposal would effectively dissolve the distinction between Jacob\'s covenant community and the Canaanite city of Shechem — exactly the kind of cultural absorption that the covenant endogamy principle (24:3; 26:34-35; 28:1) was designed to prevent.</p>',

    "10": '<p>"You can settle among us; the land is open to you. Live in it, trade in it, and acquire property in it" — Hamor offers full civic integration: residence rights, trade access, and property acquisition. These three benefits — settling, trading, owning property — were the basic components of civic belonging in ANE city-state culture. Full access to them was restricted to citizens; outsiders (like Jacob\'s household, camping outside the city) had limited rights. Hamor is offering full citizenship in exchange for the marriage alliance — a substantial economic and legal incentive.</p>',

    "11": '<p>"Let me find favor in your eyes, and I will give you whatever you ask" — Shechem\'s direct appeal to Jacob and the brothers uses the court language of favor-seeking (<em>timṣĕʾû-ḥēn bĕʿênêkem</em>), the same formula Jacob used toward Esau in ch.33. Shechem is now in the position of the supplicant, seeking approval from the family whose daughter he violated. The reversal of power — the city ruler now petitioning the semi-nomadic clan — reflects the legal reality that he needs their cooperation for the marriage he wants.</p>',

    "12": '<p>"Make the price for the bride and the gift I am to bring as great as you like" — Shechem offers an unlimited <em>mohar</em> (bride price) and <em>mattān</em> (gift). The distinction between the two terms reflects ANE marriage economics: the <em>mohar</em> was the price paid to the bride\'s family (compensating them for the loss of their daughter\'s productive labor); the <em>mattān</em> was the gift given directly to the bride herself. Shechem is essentially offering to pay whatever is needed to formalize the marriage — an acknowledgment that the violation has created a debt that must be compensated.</p>',

    "13": '<p>"Because their sister Dinah had been defiled, Jacob\'s sons replied deceitfully" — the narrator\'s explicit editorial judgment — <em>wayyanû bĕmirmāh</em> (they answered with deceit/treachery) — frames what follows as a morally labeled deception, not a legitimate negotiation. The word <em>mirmāh</em> is the same word used for Jacob\'s deception of Isaac in ch.27 (27:35: "your brother came with deceit"). The pattern of generational deception — the sons use the same instrument their father used — is not presented approvingly.</p>',

    "14": '<p>"We can\'t give our sister to a man who is not circumcised. That would be a disgrace to us" — circumcision is the Abrahamic covenant marker (Gen 17:10-14), the physical sign that distinguished Abraham\'s household from the surrounding peoples. Using it as the condition for marriage negotiation weaponizes a sacred covenant marker. The "disgrace" (<em>ḥerpāh</em>, the same word Rachel used for the disgrace of barrenness in 30:23) frames the uncircumcised status of the Shechemites as a social and covenant incompatibility. The demand is not illegitimate in itself — it would produce genuine covenant integration — but the brothers intend something else entirely.</p>',

    "15": '<p>"We will enter into an agreement with you on one condition only: that you become like us by circumcising all your males" — the brothers propose a condition that appears to offer genuine integration. If all Shechemite males were circumcised, they would bear the covenant sign of Abraham\'s household. The proposal is not a complete fraud in its stated terms — it describes a real path to covenant incorporation. The fraud is in the brothers\' intention: the condition is set knowing they plan violence, not integration.</p>',

    "16": '<p>"Then we will give you our daughters and take your daughters for ourselves. We\'ll settle among you and become one people with you" — the full intermarriage proposal echoes Hamor\'s offer in v.9. If taken at face value, it would dissolve the boundaries between Jacob\'s covenant household and Shechem\'s Canaanite city — the very outcome that covenant endogamy prevents. The brothers are describing an outcome they do not intend, making the whole negotiation a theatrical performance concealing a military plan.</p>',

    "17": '<p>"But if you will not agree to be circumcised, we\'ll take our sister and go" — the ultimatum gives the Shechemites a binary choice: circumcision or Dinah\'s return and Jacob\'s household\'s departure. The threat of departure is credible because Jacob\'s household has no legal obligation to remain near Shechem. The return of Dinah without marriage settlement was the alternative — but Dinah is currently in Shechem\'s house (v.26 notes that the brothers "took Dinah from Shechem\'s house"), suggesting she is being held or has been living there since the incident.</p>',

    "18": '<p>"Their proposal seemed good to Hamor and his son Shechem" — the Shechemites are persuaded. The proposal is presented as acceptable because (from their perspective) the economic and social benefits (full integration, property rights, intermarriage) outweigh the physical cost of circumcision. The reader, knowing the brothers\' real intention, experiences the Shechemites\' acceptance as the springing of a trap.</p>',

    "19": '<p>"The young man, who was the most honored of all his father\'s household, lost no time in doing what they said, because he was delighted with Jacob\'s daughter" — Shechem\'s social status ("most honored," <em>nikhbāḏ</em>) makes his willingness to be circumcised more significant: he is not compelling others to do what he is unwilling to do. His personal motivation (delight in Dinah) is offered as the explanation for his speed. The narrative continues to present Shechem\'s desire for Dinah as genuine — making the subsequent slaughter more morally complex rather than a simple story of justified revenge.</p>',

    "20": '<p>"So Hamor and his son Shechem went to the gate of their city to speak to the men of their city" — the city gate was the ANE\'s primary civic assembly space: legal proceedings, commercial transactions, and community decisions were conducted there. Hamor and Shechem\'s address to the community at the gate is a formal political process — they are not privately enrolling individuals but making a public proposal to the citizen body. The gate as the site of civic decision-making appears throughout the OT (Ruth 4:1-11; Prov 31:23) and in ANE texts.</p>',

    "21": '<p>"These men are friendly toward us" — Hamor\'s presentation to the city emphasizes the economic benefits (friendly trade partners, plenty of land) without foregrounding the full context. The word <em>šĕlēmîm</em> (peaceful, friendly) is the masculine plural of the word for shalom — Hamor is vouching for Jacob\'s household as harmless, a characterization that will prove catastrophically wrong. The presentation omits Shechem\'s violation of Dinah — the precipitating cause of the negotiation is not disclosed to the citizens who will pay the price.</p>',

    "22": '<p>"The men will agree to live with us as one people only on the condition that our males be circumcised, as they themselves are" — Hamor faithfully reports the condition, though v.23\'s economic argument suggests his motivation in presenting it. The two-sided nature of the proposal — they circumcise, Jacob\'s household integrates — is what makes it persuasive to the community. From the Shechemites\' perspective, it is a negotiated settlement between communities, not a trap.</p>',

    "23": '<p>"Won\'t their livestock, their property and all their other animals become ours?" — Hamor\'s economic argument is the selling point: Jacob\'s household wealth (substantial from the Laban years) will become communally accessible once they are fully integrated. The argument is that circumcision is a temporary physical cost that will yield permanent economic benefit. The irony is precise: in v.28, the brothers seize exactly those livestock and animals as plunder. Hamor\'s economic promise to his citizens becomes the description of what they lose.</p>',

    "24": '<p>"All the men who went out of the city gate agreed with Hamor and his son Shechem, and every male in the city was circumcised" — the unanimous circumcision of the entire male population follows the civic decision made at the gate. The phrase "all the men who went out of the city gate" (<em>kol-yōṣĕʾê šaʿar ʿîrô</em>) — the city\'s full male citizen body — indicates complete community participation. The circumcision is not a token compliance but a total commitment. The covenant sign of Abraham\'s people has now been applied to an entire Canaanite population — under false pretenses, by both sides of the negotiation.</p>',

    "25": '<p>"Three days later, while all of them were still in pain, two of Jacob\'s sons, Simeon and Levi, Dinah\'s brothers, took their swords and attacked the unsuspecting city, killing every male" — the third day after circumcision is the most physically debilitating. ANE medical knowledge recognized this; the timing of the attack on the third day was deliberate military intelligence applied to a specific vulnerability. "Unsuspecting" (<em>beṭaḥ</em>, in security/safety) — the city was not on a military footing; they had just concluded what they believed was a peaceful integration agreement. Simeon and Levi are identified specifically as "Dinah\'s brothers" — children of Leah, full brothers to Dinah, with a specific honor-obligation to defend their full sister.</p>',

    "26": '<p>"They put Hamor and his son Shechem to the sword and took Dinah from Shechem\'s house and left" — the targeting of Hamor and Shechem specifically (the ruler and his son who violated and detained Dinah) is distinguished from the general massacre. Dinah\'s removal "from Shechem\'s house" confirms she has been held there — whether voluntarily or as a de facto hostage during the negotiations. The phrase raises the question of Dinah\'s own experience and voice, which the narrative does not give her.</p>',

    "27": '<p>"The sons of Jacob came upon the dead and looted the city where their sister had been defiled" — after Simeon and Levi\'s military action, the rest of Jacob\'s sons participate in plundering the city. The looting follows the ANE practice of taking enemy property after military victory; it extends the punishment from the specific perpetrators (Hamor and Shechem) to the entire community. The narrator\'s framing — "where their sister had been defiled" — maintains the justificatory connection between the plunder and the original wrong.</p>',

    "28": '<p>"They seized their flocks and herds and donkeys and everything else of theirs in the city and out in the fields" — the specific list of plunder — flocks, herds, donkeys, city property, field property — is exactly the wealth catalog that Hamor promised his citizens would become theirs through integration (v.23). The economic logic is inverted: instead of Jacob\'s household\'s wealth flowing into Shechem, Shechem\'s wealth flows out to Jacob\'s household. The irony underscores the catastrophic miscalculation of Hamor\'s economic argument.</p>',

    "29": '<p>"They carried off all their wealth and all their women and children, taking as plunder everything in the houses" — the capture of women and children as slaves was standard ANE warfare practice; it does not mean the narrator endorses it. The totality of the plunder — wealth, women, children, household goods — leaves the city of Shechem stripped. What began as a negotiation for one woman\'s marriage ends with the forced displacement of an entire city\'s women and children.</p>',

    "30": '<p>"You have brought trouble on me by making me obnoxious to the Canaanites and Perizzites" — Jacob\'s rebuke to Simeon and Levi is entirely pragmatic: his concern is his own safety and reputation (<em>ʿăkhartem ʾōtî</em>, you have made me a stink/trouble), not the ethics of the massacre or the wellbeing of the Shechemite women and children. "We are few in number" — Jacob\'s household is demographically vulnerable; a coalition of Canaanite city-states in retaliation could destroy them. The rebuke reveals Jacob\'s self-protective orientation; he has no moral argument to offer, only a survival argument.</p>',

    "31": '<p>"Should he have treated our sister like a prostitute?" — Simeon and Levi\'s rhetorical counter challenges Jacob\'s silence on the moral substance. The word "prostitute" (<em>zônāh</em>) captures what Shechem\'s violation without immediate marriage would have meant socially: treating Dinah as sexually available without covenant status — a woman without honor-protection. Their counter argues that Jacob\'s pragmatic concern for his own safety failed to address the fundamental covenant wrong. The narrative ends without resolution — both positions are stated; neither is adjudicated by the narrator, leaving the reader to weigh the competing claims. Gen 49:5-7 revisits this, where Jacob curses Simeon and Levi for the violence at Shechem.</p>',
  },
  "35": {
    "1": '<p>"Go up to Bethel and settle there, and build an altar there to God, who appeared to you when you were fleeing from your brother Esau" — YHWH\'s command is the fulfillment of Jacob\'s Bethel vow (28:20-22): twenty years later, Jacob is directed to return and complete what he promised. The divine reminder of the original theophany ("when you were fleeing from your brother Esau") connects the current command to the entire arc of Jacob\'s life. The urgency of the command — given immediately after the Shechem crisis — suggests that the altar at Bethel is the proper resolution to the household\'s religious and social disorder.</p>',

    "2": '<p>"Get rid of the foreign gods you have with you, and purify yourselves and change your clothes" — the household purification before approaching Bethel involves three actions: removal of foreign gods (<em>ʾĕlōhê hannēkhār</em>, gods of foreigners/strangers), ritual purification (<em>hiṭṭahărû</em>), and change of garments. Foreign gods in the household included Rachel\'s teraphim (31:19, 34-35) and possibly others acquired during the Paddan-Aram period. Change of garments was an ANE purification ritual marking transition between profane and sacred states — worn, travel-stained clothing was replaced before approaching a deity\'s sanctuary. The threefold preparation mirrors Sinai preparations (Exod 19:10-14).</p>',

    "3": '<p>"Who answered me in the day of my distress and who has been with me wherever I have gone" — Jacob\'s summary of YHWH\'s character in the theophany-fulfillment is a covenant-fidelity formula: the God who answered (<em>ʿānānî</em>) when Jacob called, and who accompanied (<em>hāyāh ʿimmāḏî</em>, was with me) throughout the years in Haran. "The day of my distress" (<em>bĕyôm ṣārātî</em>) refers to the Bethel night — the flight from Esau — which is the same event YHWH referenced in v.1. Jacob frames the altar as the response to a fulfilled covenant, not an obligation fulfilled under compulsion.</p>',

    "4": '<p>"They gave Jacob all the foreign gods they had and the rings in their ears, and Jacob buried them under the oak at Shechem" — the earrings (<em>nĕzāmîm</em>) are buried alongside the idols, indicating they functioned as religious objects — amulets, charms, or ornaments associated with Mesopotamian deities. In the ANE, jewelry was often votive or apotropaic (protective against evil); earrings bearing divine images or associated with fertility goddesses were common. The oak at Shechem — already significant as the location where Abraham received the covenant promise (12:6: "the great tree of Moreh at Shechem") — becomes a burial site for the covenant household\'s foreign religious objects, a repudiation enacted at the same ground where Abraham\'s covenant was first announced.</p>',

    "5": '<p>"The terror of God fell on the towns all around them so that no one pursued them" — <em>ḥittat ʾĕlōhîm</em> (terror/dread of God) is the divine protection mechanism for a vulnerable journey. The same concept appears in Exod 23:27 ("I will send my terror ahead of you and throw into confusion every nation you encounter") and in the Song of Moses (Exod 15:14-16, where surrounding peoples are seized with dread at YHWH\'s power). Jacob\'s household was at maximum vulnerability — the Shechem massacre had made them potential targets for regional coalition retaliation. The divine terror prevents any retaliatory pursuit.</p>',

    "6": '<p>"Jacob and all the people with him came to Luz (that is, Bethel) in the land of Canaan" — the narrator uses both names (Luz = the pre-Israelite name; Bethel = Jacob\'s sacred name from ch.28) to establish continuity between the sites. The return to Bethel closes the narrative arc that began with Jacob\'s flight in 28:10. The household that left Canaan as a single man with a staff (32:10) returns as a large household with wives, children, servants, and flocks — the fulfillment of the covenant promises enacted in the twenty years of absence.</p>',

    "7": '<p>"He called the place El Bethel" — the altar name "God of Bethel" (<em>ʾēl bêt-ʾēl</em>) is a divine epithet derived from the location. The same title appears in Hosea 12:4 (where YHWH reminds Israel of the Bethel encounter). The altar naming continues the Genesis pattern of commemorative naming at sites of divine encounter (12:8; 13:18; 21:33; 26:25); each altar marks a place where the covenant was actualized in history.</p>',

    "8": '<p>"Deborah, Rebekah\'s nurse, died and was buried under the oak outside Bethel. So it was named Allon Bakuth" — Deborah was last mentioned traveling with Rebekah from Haran (24:59); now, decades later, she dies and is buried under an oak beside Bethel. How she came to be with Jacob\'s household is not explained — possibly Rebekah had died and Deborah passed to Jacob\'s care, or she had been with the household throughout. The burial name <em>ʾallôn bākhût</em> (oak of weeping) is unique: servants were rarely memorialized by place-name in ANE narrative. The tenderness of the grief expressed signals that Deborah was a significant household presence whose loss was genuinely mourned.</p>',

    "9": '<p>"After Jacob returned from Paddan Aram, God appeared to him again and blessed him" — the second Bethel theophany formally closes the Paddan-Aram cycle. The "again" (<em>ʿôḏ</em>) connects this appearance to the first Bethel theophany (28:13-22). The blessing is the divine action that ratifies the covenant renewal — the same pattern of theophany → blessing → covenant promises → naming that structured the original encounter.</p>',

    "10": '<p>"Your name is Jacob, but you will no longer be called Jacob; your name will be Israel. So he named him Israel" — the official divine renaming formalizes what the angel announced at Peniel (32:28). In the ANE, a divine renaming was a covenant act that redefined the person\'s identity and role — Abram to Abraham (17:5), Sarai to Sarah (17:15). The formal Bethel renaming gives Israel its covenant identity in the precise location where the covenant was first announced to Jacob; it is the theological completion of the arc from 28:13 to 35:10.</p>',

    "11": '<p>"I am God Almighty; be fruitful and increase in number. A nation and a community of nations will come from you, and kings will be among your descendants" — <em>ʾEl-Šaddai</em> (God Almighty) is the covenant name used in Abraham\'s covenant establishment (17:1) and Isaac\'s blessing of Jacob for his journey (28:3). Its use here at Bethel ties the three patriarchs\' covenant encounters together under the same divine name. "A community of nations" (<em>qĕhal gôyîm</em>) and "kings" among the descendants are the covenant expansions — the tribal and royal dimensions that the twelve-tribe nation and the Davidic monarchy will fulfill.</p>',

    "12": '<p>"The land I gave to Abraham and Isaac I also give to you, and I will give this land to your descendants after you" — the land promise is renewed for the third generation. The explicit linking of all three patriarchs ("I gave to Abraham and Isaac") makes Jacob\'s covenant standing historically cumulative — he does not receive a new covenant but the same covenant confirmed through three generations. The word <em>ʾetten</em> (I give) is in the perfect tense in some manuscripts, indicating a completed gift; in others, imperfect — reflecting the ongoing and future nature of the promise.</p>',

    "13": '<p>"Then God went up from him at the place where he had talked with him" — the divine departure marks the end of the theophany. "Went up" (<em>wayyaʿal</em>) reflects the vertical cosmology of ANE divine encounters: God descends to meet humans and returns to the divine realm above. The phrase is used for YHWH\'s departure in Exod 24:18 (Moses ascending to God) and in Elijah\'s context; it marks the formal close of a divine-human encounter rather than a simple end to the conversation.</p>',

    "14": '<p>"Jacob set up a stone pillar at the place where God had talked with him, and he poured out a drink offering on it; he also poured oil on it" — the pillar (<em>maṣṣēḇāh</em>) echoes the one Jacob set up at the original Bethel theophany (28:18), when he anointed it with oil. Here a drink offering (<em>nesekh</em>) is added — the first mention of a drink offering in Genesis. Drink offerings (wine poured on the altar) became a standard component of the Mosaic worship system (Num 15:5-10); Jacob\'s addition here prefigures that practice. The pillar + oil + drink offering is a fuller ceremonial marking than the original simple anointing.</p>',

    "15": '<p>"Jacob called the place where God had talked with him Bethel" — the naming confirms 28:19 (where Jacob first called it Bethel) and functions as a renewed dedication of the name: the place is now doubly named Bethel, by the young man fleeing his brother and by the returning patriarch. Bethel will remain a major cultic site in Israelite history: the ark of the covenant is kept there during the period of judges (Judg 20:26-28); Jeroboam later installs a golden calf there (1 Kgs 12:29), and the prophets condemn it (Hos 4:15; Amos 4:4; 5:5).</p>',

    "16": '<p>"They moved on from Bethel. While they were still some distance from Ephrath, Rachel began to give birth and had great difficulty" — Ephrath (later identified as Bethlehem, v.19) is in the central highlands south of Jerusalem. The journey from Bethel to Ephrath is approximately 10-15 miles through difficult terrain. Rachel\'s labor begins mid-journey — the most vulnerable possible time for a difficult birth in the ancient world, far from settled shelter. "Great difficulty" (<em>wattĕqaš bĕliḏtāh</em>) indicates a complicated, prolonged labor — the kind that threatened both mother and child.</p>',

    "17": '<p>"The midwife said to her, \'Don\'t despair, for you have another son\'" — midwives (<em>mĕyalleḏet</em>, the one who brings forth) were a recognized professional category in the ANE. Egyptian papyri and Mesopotamian texts describe midwives\' roles; Exod 1:15-21 names two Hebrew midwives (Shiphrah and Puah). The midwife\'s role included encouragement during labor — "don\'t despair" (<em>ʾal-tîrĕʾî</em>, don\'t be afraid) is also the formula used elsewhere in Genesis for divine reassurance (15:1; 21:17; 26:24). The announcement of "another son" was important news in an era when son-bearing defined a wife\'s social standing; for Rachel, who prayed for children throughout chs.29-30, the news is simultaneously fulfilling and final.</p>',

    "18": '<p>"As she breathed her last — for she was dying — she named her son Ben-Oni. But his father named him Benjamin" — Rachel\'s naming of Ben-Oni (<em>ben-ʾônî</em>, son of my sorrow/suffering) is her dying act. The name encodes her experience: this birth cost her life. Jacob immediately overrides the name with Benjamin (<em>binyāmîn</em>): either "son of the right hand" (the right hand being the honored or powerful side — cf. the blessing position in 48:14) or "son of the south" (yāmîn as south, since Benjamin\'s territory is in the south of the later tribal allocation). Jacob\'s renaming is a paternal assertion of authority over the child\'s identity — he refuses to let Rachel\'s death-grief define the child\'s name and destiny.</p>',

    "19": '<p>"Rachel died and was buried on the way to Ephrath (that is, Bethlehem)" — Rachel\'s burial "on the way" (<em>bĕderekh</em>) rather than in the family burial cave at Machpelah is a significant departure from the patriarchal burial pattern. Jer 31:15 memorializes this location: "A voice is heard in Ramah, weeping and great mourning, Rachel weeping for her children." The "Ramah" of Jeremiah is near Bethlehem, in the territory of Benjamin — Rachel\'s own son\'s tribal land. In 1 Sam 10:2, Samuel points Saul to Rachel\'s tomb as a landmark in Benjamin\'s territory, confirming the geographic memory of this burial site.</p>',

    "20": '<p>"Over her tomb Jacob set up a pillar, and to this day that pillar marks Rachel\'s tomb" — the third pillar Jacob erects in Genesis (the first was at Bethel in 28:18; the second at Bethel in 35:14; this is at Rachel\'s tomb). The phrase "to this day" (<em>ʿad-hayyôm</em>) is a narrative marker indicating that the pillar was a landmark known to the original audience at the time of writing. The pillar at Rachel\'s tomb is a memorial that transforms a spot of grief into a covenant landmark — her death, like Abraham\'s purchase of Machpelah, marks the patriarchal family\'s claim on Canaan\'s soil.</p>',

    "21": '<p>"Israel moved on again and pitched his tent beyond Migdal Eder" — Migdal Eder (<em>migdal-ʿēḏer</em>, tower of the flock) is a shepherds\' watchtower south of Bethlehem, mentioned in Mic 4:8 as a future gathering point for the restored Israel. The stop here — between Rachel\'s death and the Reuben incident of v.22 — is a transitional note marking Jacob\'s movement southward toward Hebron and Isaac\'s household.</p>',

    "22": '<p>"Reuben went in and slept with his father\'s concubine Bilhah, and Israel heard of it" — sleeping with a father\'s concubine or wife was an ANE act of political and social dominance: claiming the subordinate women of a household was a recognized way of asserting claim to the patriarch\'s position or inheritance. Absalom\'s sleeping with David\'s concubines (2 Sam 16:21-22) was explicitly political — Ahithophel frames it as demonstrating that Absalom\'s revolt is irreversible. Reuben, as Jacob\'s firstborn (29:32), may be asserting his claim to succession following Rachel\'s death. Jacob\'s silence — "Israel heard of it" — without recorded response suggests either emotional exhaustion (he has just buried Rachel) or a deferred judgment (given at his deathbed in 49:3-4, where Reuben loses his firstborn privileges for this act).</p>',

    "23": '<p>"The sons of Leah: Reuben the firstborn of Jacob, Simeon, Levi, Judah, Issachar and Zebulun" — the formal tribal inventory follows immediately after the Reuben incident, a placement that simultaneously lists Reuben as firstborn and contextualizes the incident that will end his firstborn privileges. The enumeration by mother groups mirrors the structure of Numbers 1 (the tribal census) and Deut 33 (the tribal blessings). The six sons of Leah are the largest maternal group, reflecting her greater fertility throughout chs.29-30.</p>',

    "24": '<p>"The sons of Rachel: Joseph and Benjamin" — Rachel\'s two sons are listed together, united by being the sons of the beloved wife. Joseph (30:24) was born in Paddan-Aram during the Laban years; Benjamin was just born here, in Canaan, after Rachel\'s death. The pairing of Joseph and Benjamin — both born of Rachel, both geographically separated from the other ten brothers\' births — prefigures the special relationship between them in the Joseph narrative (42:4; 43:14-16; 44:20-34).</p>',

    "25": '<p>"The sons of Rachel\'s servant Bilhah: Dan and Naphtali" — the two sons of Rachel\'s surrogate are listed as Rachel\'s sons in the tribal enumeration, consistent with the ANE surrogate-mother convention: children born through the maidservant to the mistress\'s account were legally the mistress\'s children. Dan and Naphtali appear here as "sons of Rachel" (via surrogate) in the formal list, reflecting their legal status even though Bilhah was their biological mother.</p>',

    "26": '<p>"The sons of Leah\'s servant Zilpah: Gad and Asher. These were the sons of Jacob, born to him in Paddan Aram" — the final summary covers all twelve sons. The concluding note "born to him in Paddan Aram" is technically inaccurate for Benjamin (born in Canaan in v.16-18); it likely refers to the majority of the sons or to the formation of the family unit in Paddan-Aram. The twelve-tribe list here is the formal narrative completion of the tribal origin account that began in 29:32.</p>',

    "27": '<p>"Jacob came home to his father Isaac in Mamre, near Kiriath Arba (that is, Hebron), where Abraham and Isaac had stayed" — the return to Isaac closes the Paddan-Aram cycle. Mamre/Hebron is the patriarchal home: Abraham lived at Mamre (13:18; 18:1); Isaac settled at Hebron after the Abimelech period (26:23; 35:27). Jacob\'s return to his father after twenty years away (28:10; 31:38) is a homecoming that the narrative has anticipated since Jacob\'s departure. The identification "where Abraham and Isaac had stayed" frames Hebron as the ancestral covenant seat.</p>',

    "28": '<p>"Isaac lived a hundred and eighty years" — Isaac\'s lifespan of 180 years exceeds Abraham\'s 175 (25:7) by five years. The patriarchal lifespans in Genesis follow a descending arc from the antediluvian numbers (Methuselah\'s 969, Noah\'s 950) through the early post-flood period to the patriarchs\' still-impressive but more bounded centuries. Isaac\'s 180 years represent a full and complete life in the ANE reckoning — 180 is a highly composite number (60 × 3, 36 × 5) with numerical prestige in ancient Babylonian mathematics.</p>',

    "29": '<p>"He breathed his last and died and was gathered to his people, old and full of years. And his sons Esau and Jacob buried him" — the burial formula for Isaac ("gathered to his people") echoes Abraham\'s death notice (25:8) — the standard euphemism for death in Genesis. That both Esau and Jacob buried Isaac echoes Ishmael and Isaac burying Abraham (25:9) — in both cases, estranged half-brothers or deceiving brothers are reunited at their father\'s death to perform the burial. The family burial marks the patriarchal generation\'s closure: Abraham is already gone; Isaac has now died; Jacob\'s generation carries the covenant forward.</p>',
  }
}

def main():
    existing = load_comm('mkt-context', 'genesis')
    merge_comm(existing, GENESIS)
    save_comm('mkt-context', 'genesis', existing)
    print('Genesis 33-35 mkt-context written.')

if __name__ == '__main__':
    main()
